  <text x="200" y="100" font-size="13" font-family="system-ui,sans-serif">6</text>
  <text x="55" y="100" font-size="13" font-family="system-ui,sans-serif">?</text>
  <text x="215" y="162" font-size="12" font-family="system-ui,sans-serif">60°</text>
</svg>', 'diagram', '[{"id":"A","text":"$${angle}°$","is_correct":false,"explanation":"That is angle A, not C."},{"id":"B","text":"$60°$","is_correct":false,"explanation":"That is angle B."},{"id":"C","text":"$${angle + 10}°$","is_correct":false,"explanation":"Triangle angles must sum to 180°; this is too large."},{"id":"D","text":"$${unknown}°$","is_correct":true,"explanation":"$96° + 60° + 24° = 180°$."}]'::jsonb, 'D', 'Angles in a triangle sum to $180°$: $m\angle C = 180 - 96 - 60 = 24°$.', NULL, 'Geometry and Trigonometry', 'Lines, angles, and triangles', 'math', 'geometry', 'LIN_G', 'LIN_G', 'hard', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_template_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
